// Some portions generated by Claude
package org.eclipse.rdf4j.sail.lmdb;

import static org.junit.jupiter.api.Assertions.assertEquals;
import static org.junit.jupiter.api.Assertions.assertTrue;

import java.io.File;
import java.util.List;
import java.util.Map;

import org.eclipse.rdf4j.model.IRI;
import org.eclipse.rdf4j.model.ValueFactory;
import org.eclipse.rdf4j.model.impl.SimpleValueFactory;
import org.eclipse.rdf4j.query.algebra.Count;
import org.eclipse.rdf4j.query.algebra.Group;
import org.eclipse.rdf4j.query.algebra.GroupElem;
import org.eclipse.rdf4j.query.algebra.Service;
import org.eclipse.rdf4j.query.algebra.StatementPattern;
import org.eclipse.rdf4j.query.algebra.TripleRef;
import org.eclipse.rdf4j.query.algebra.Var;
import org.eclipse.rdf4j.query.algebra.evaluation.impl.EvaluationStatistics;
import org.eclipse.rdf4j.repository.sail.SailRepository;
import org.eclipse.rdf4j.repository.sail.SailRepositoryConnection;
import org.eclipse.rdf4j.sail.lmdb.config.LmdbStoreConfig;
import org.junit.jupiter.api.AfterEach;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;
import org.junit.jupiter.api.io.TempDir;

/**
 * Cardinality estimates for operators the LMDB calculator previously left to the base-class placeholder heuristics: a
 * constant-endpoint SERVICE must never look more selective than a local index lookup, GROUP BY must collapse below its
 * input, and a triple reference should use the store-backed statement count as its proxy.
 */
class LmdbOpaqueOperatorCardinalityTest {

	private static final ValueFactory VF = SimpleValueFactory.getInstance();
	private static final IRI NAME = VF.createIRI("urn:test:name");
	private static final int SUBJECT_COUNT = 120;

	@TempDir
	File dataDir;

	private LmdbStore store;
	private SailRepository repository;
	private EvaluationStatistics statistics;

	@BeforeEach
	void setUp() {
		store = new LmdbStore(dataDir, new LmdbStoreConfig("spoc,posc"));
		repository = new SailRepository(store);
		repository.init();
		try (SailRepositoryConnection connection = repository.getConnection()) {
			connection.begin();
			for (int i = 0; i < SUBJECT_COUNT; i++) {
				connection.add(VF.createIRI("urn:test:s" + i), NAME, VF.createLiteral("name" + (i % 4)));
			}
			connection.commit();
		}
		statistics = store.getBackingStore().getEvaluationStatistics();
	}

	@AfterEach
	void tearDown() {
		repository.shutDown();
	}

	@Test
	void constantEndpointServiceIsNeverEstimatedAsSelective() {
		StatementPattern remote = new StatementPattern(new Var("x"), new Var("p", NAME), new Var("n"));
		Service service = new Service(new Var("endpoint", VF.createIRI("http://example.com/sparql")), remote,
				"?x <urn:test:name> ?n", Map.of(), null, false);

		double cardinality = statistics.getCardinality(service);

		assertTrue(cardinality >= 1_000.0d,
				"A remote SERVICE call has unknown result size and network latency; it must never be costed as "
						+ "more selective than a local index lookup, but was estimated at " + cardinality);
	}

	@Test
	void keyedGroupByCollapsesBelowItsInput() {
		StatementPattern names = new StatementPattern(new Var("s"), new Var("p", NAME), new Var("n"));
		double inputRows = statistics.getCardinality(names);
		assertTrue(inputRows > 10.0d, "Sanity: the name scan should be estimated well above ten rows: " + inputRows);

		Group group = new Group(names.clone(), List.of("n"),
				List.of(new GroupElem("c", new Count(new Var("s")))));
		double groupRows = statistics.getCardinality(group);

		assertTrue(groupRows < inputRows,
				"GROUP BY collapses rows per key and must be estimated below its input (input=" + inputRows
						+ ", group=" + groupRows + ")");
	}

	@Test
	void keylessGroupByProducesOneRow() {
		StatementPattern names = new StatementPattern(new Var("s"), new Var("p", NAME), new Var("n"));
		Group group = new Group(names, List.of(), List.of(new GroupElem("c", new Count(new Var("s")))));

		assertEquals(1.0d, statistics.getCardinality(group),
				"Aggregation without GROUP BY always yields exactly one row");
	}

	@Test
	void tripleRefUsesStatementCountAsStoreBackedProxy() {
		TripleRef tripleRef = new TripleRef(new Var("s"), new Var("p", NAME),
				new Var("o", VF.createLiteral("name1")), new Var("t"));
		StatementPattern proxy = new StatementPattern(new Var("s"), new Var("p", NAME),
				new Var("o", VF.createLiteral("name1")));

		assertEquals(statistics.getCardinality(proxy), statistics.getCardinality(tripleRef),
				"Without a dedicated triple-term index, the matching statement count is the store-backed proxy "
						+ "for a triple reference");
	}
}
